import React, { useState } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Alert,
  CircularProgress,
  Divider,
  Container,
  Tab,
  Tabs,
} from '@mui/material';
import fetchModel from '../../lib/fetchModelData';
import './styles.css';

function LoginRegister({ onLoginSuccess }) {
  // State quản lý tab (Login / Register)
  const [tabValue, setTabValue] = useState(0);

  // State cho form Đăng ký
  const [registerForm, setRegisterForm] = useState({
    login_name: '',
    password: '',
    confirm_password: '',
    first_name: '',
    last_name: '',
  });

  // State cho form Đăng nhập
  const [loginForm, setLoginForm] = useState({
    login_name: '',
    password: '',
  });

  // State cho thông báo lỗi/thành công
  const [registerMessage, setRegisterMessage] = useState({
    type: '', // 'success', 'error'
    text: '',
  });

  const [loginMessage, setLoginMessage] = useState({
    type: '',
    text: '',
  });

  // State cho loading
  const [isRegisterLoading, setIsRegisterLoading] = useState(false);
  const [isLoginLoading, setIsLoginLoading] = useState(false);

  // ===== ĐĂNG KÝ =====
  const handleRegisterChange = (e) => {
    const { name, value } = e.target;
    setRegisterForm((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleRegisterSubmit = async (e) => {
    e.preventDefault();
    setRegisterMessage({ type: '', text: '' });

    // Kiểm tra validate cơ bản
    if (
      !registerForm.login_name.trim() ||
      !registerForm.password.trim() ||
      !registerForm.confirm_password.trim()
    ) {
      setRegisterMessage({
        type: 'error',
        text: 'Vui lòng điền đầy đủ thông tin bắt buộc',
      });
      return;
    }

    // Kiểm tra mật khẩu khớp
    if (registerForm.password !== registerForm.confirm_password) {
      setRegisterMessage({
        type: 'error',
        text: 'Mật khẩu xác nhận không khớp!',
      });
      return;
    }

    // Kiểm tra độ dài mật khẩu
    if (registerForm.password.length < 6) {
      setRegisterMessage({
        type: 'error',
        text: 'Mật khẩu phải tối thiểu 6 ký tự',
      });
      return;
    }

    setIsRegisterLoading(true);

    try {
      // Gọi API đăng ký
      const response = await fetchModel('/user', 'POST', {
        login_name: registerForm.login_name,
        password: registerForm.password,
        first_name: registerForm.first_name,
        last_name: registerForm.last_name,
      });

      // Thành công
      setRegisterMessage({
        type: 'success',
        text: '✅ Đăng ký thành công! Vui lòng đăng nhập.',
      });

      // Xóa form
      setRegisterForm({
        login_name: '',
        password: '',
        confirm_password: '',
        first_name: '',
        last_name: '',
      });

      // Chuyển sang tab Đăng nhập sau 2 giây
      setTimeout(() => {
        setTabValue(0);
      }, 2000);
    } catch (err) {
      // Lỗi
      setRegisterMessage({
        type: 'error',
        text: `❌ ${err.message || 'Đăng ký thất bại'}`,
      });
    } finally {
      setIsRegisterLoading(false);
    }
  };

  // ===== ĐĂNG NHẬP =====
  const handleLoginChange = (e) => {
    const { name, value } = e.target;
    setLoginForm((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleLoginSubmit = async (e) => {
    e.preventDefault();
    setLoginMessage({ type: '', text: '' });

    if (!loginForm.login_name.trim() || !loginForm.password.trim()) {
      setLoginMessage({
        type: 'error',
        text: 'Vui lòng nhập đầy đủ tên đăng nhập và mật khẩu',
      });
      return;
    }

    setIsLoginLoading(true);

    try {
      // TODO: Gọi API đăng nhập khi API này được tạo
      // Hiện tại tạm mock thành công
      setLoginMessage({
        type: 'success',
        text: '✅ Đăng nhập thành công!',
      });

      // Lưu thông tin user (tạm thời)
      localStorage.setItem('currentUser', JSON.stringify({
        login_name: loginForm.login_name,
      }));

      // Gọi callback nếu đăng nhập thành công
      if (onLoginSuccess) {
        onLoginSuccess({
          login_name: loginForm.login_name,
        });
      }
    } catch (err) {
      setLoginMessage({
        type: 'error',
        text: `❌ ${err.message || 'Đăng nhập thất bại'}`,
      });
    } finally {
      setIsLoginLoading(false);
    }
  };

  return (
    <Container maxWidth="sm" className="login-register-container">
      <Paper elevation={3} sx={{ p: 4, mt: 4 }}>
        <Typography variant="h4" textAlign="center" gutterBottom sx={{ fontWeight: 'bold', mb: 3 }}>
          📸 Photo Sharing
        </Typography>

        {/* Tabs */}
        <Tabs
          value={tabValue}
          onChange={(e, newValue) => setTabValue(newValue)}
          variant="fullWidth"
          sx={{ mb: 3 }}
        >
          <Tab label="🔐 Đăng Nhập" />
          <Tab label="✍️ Đăng Ký" />
        </Tabs>

        {/* ===== TAB ĐĂNG NHẬP ===== */}
        {tabValue === 0 && (
          <Box component="form" onSubmit={handleLoginSubmit}>
            <Typography variant="h6" sx={{ mb: 2 }}>
              Đăng nhập tài khoản
            </Typography>

            {loginMessage.text && (
              <Alert severity={loginMessage.type} sx={{ mb: 2 }}>
                {loginMessage.text}
              </Alert>
            )}

            <TextField
              fullWidth
              label="Tên đăng nhập"
              name="login_name"
              type="text"
              value={loginForm.login_name}
              onChange={handleLoginChange}
              margin="normal"
              placeholder="Nhập tên đăng nhập của bạn"
              disabled={isLoginLoading}
            />

            <TextField
              fullWidth
              label="Mật khẩu"
              name="password"
              type="password"
              value={loginForm.password}
              onChange={handleLoginChange}
              margin="normal"
              placeholder="Nhập mật khẩu"
              disabled={isLoginLoading}
            />

            <Button
              fullWidth
              variant="contained"
              color="primary"
              type="submit"
              sx={{ mt: 3 }}
              disabled={isLoginLoading}
            >
              {isLoginLoading ? <CircularProgress size={24} /> : 'Đăng Nhập'}
            </Button>

            <Typography variant="body2" textAlign="center" sx={{ mt: 2, color: 'text.secondary' }}>
              Chưa có tài khoản? <span style={{ cursor: 'pointer', color: '#1976d2' }} onClick={() => setTabValue(1)}>Đăng ký</span>
            </Typography>
          </Box>
        )}

        {/* ===== TAB ĐĂNG KÝ ===== */}
        {tabValue === 1 && (
          <Box component="form" onSubmit={handleRegisterSubmit}>
            <Typography variant="h6" sx={{ mb: 2 }}>
              Tạo tài khoản mới
            </Typography>

            {registerMessage.text && (
              <Alert severity={registerMessage.type} sx={{ mb: 2 }}>
                {registerMessage.text}
              </Alert>
            )}

            <TextField
              fullWidth
              label="Tên đăng nhập *"
              name="login_name"
              type="text"
              value={registerForm.login_name}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Chọn tên đăng nhập"
              disabled={isRegisterLoading}
              required
            />

            <TextField
              fullWidth
              label="Mật khẩu *"
              name="password"
              type="password"
              value={registerForm.password}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Ít nhất 6 ký tự"
              disabled={isRegisterLoading}
              required
            />

            <TextField
              fullWidth
              label="Xác nhận mật khẩu *"
              name="confirm_password"
              type="password"
              value={registerForm.confirm_password}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Nhập lại mật khẩu"
              disabled={isRegisterLoading}
              required
            />

            <Divider sx={{ my: 2 }}>Thông tin cá nhân (không bắt buộc)</Divider>

            <TextField
              fullWidth
              label="Tên"
              name="first_name"
              type="text"
              value={registerForm.first_name}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Tên của bạn"
              disabled={isRegisterLoading}
            />

            <TextField
              fullWidth
              label="Họ"
              name="last_name"
              type="text"
              value={registerForm.last_name}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Họ của bạn"
              disabled={isRegisterLoading}
            />

            <Button
              fullWidth
              variant="contained"
              color="success"
              type="submit"
              sx={{ mt: 3 }}
              disabled={isRegisterLoading}
            >
              {isRegisterLoading ? <CircularProgress size={24} /> : 'Đăng Ký'}
            </Button>

            <Typography variant="body2" textAlign="center" sx={{ mt: 2, color: 'text.secondary' }}>
              Đã có tài khoản? <span style={{ cursor: 'pointer', color: '#1976d2' }} onClick={() => setTabValue(0)}>Đăng nhập</span>
            </Typography>
          </Box>
        )}
      </Paper>
    </Container>
  );
}

export default LoginRegister;
